from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a fluent sentence from a list of triples."""
    if not triples:
        return ""
    sentences = []
    for t in triples:
        s, p, o = t.subject, t.predicate, t.object
        # Simple verbalisation rules for common predicates
        if p == "birthDate":
            phrase = f"{s} was born on {o}"
        elif p == "deathDate":
            phrase = f"{s} died on {o}"
        elif p == "birthPlace":
            phrase = f"{s} was born in {o}"
        elif p == "deathPlace":
            phrase = f"{s} died in {o}"
        elif p == "origin":
            phrase = f"{s} originates from {o}"
        elif p == "genre":
            phrase = f"{s} performs {o} music"
        elif p == "instrument":
            phrase = f"{s} plays the {o}"
        elif p == "occupation":
            phrase = f"{s} works as {o}"
        elif p == "nationality":
            phrase = f"{s} is {o}"
        elif p == "associatedBand/associatedMusicalArtist":
            phrase = f"{s} is associated with {o}"
        else:
            phrase = f"{s} {p} {o}"
        sentences.append(phrase)
    # Combine parts into a single fluent sentence
    if len(sentences) == 1:
        return sentences[0] + "."
    return ", ".join(sentences[:-1]) + ", and " + sentences[-1] + "."

# EVOLVE-BLOCK-END

